function solve(points) {
    const MOD = 10**9 + 7;
    const map = new Map();

    // Group points by their y-coordinate
    for (const [x, y] of points) {
        if (!map.has(y)) {
            map.set(y, []);
        }
        map.get(y).push(x);
    }

    // Count the number of horizontal lines (same y-coordinate)
    let horizontalLines = 0;
    for (const y of map.keys()) {
        const xs = map.get(y);
        if (xs.length >= 2) {
            horizontalLines += (xs.length * (xs.length - 1)) / 2;
        }
    }

    // Count the number of horizontal trapezoids
    let result = 0;
    for (const y of map.keys()) {
        const xs = map.get(y);
        const n = xs.length;
        if (n < 2) continue;

        // For each pair of horizontal lines, count the number of trapezoids
        for (const y2 of map.keys()) {
            if (y2 === y) continue;
            const xs2 = map.get(y2);
            const m = xs2.length;
            if (m < 2) continue;

            // For each pair of points on the first line and each pair of points on the second line
            // If the pairs are non-overlapping, they form a trapezoid
            // We count the number of such combinations
            const count = (n * (n - 1) / 2) * (m * (m - 1) / 2);
            result = (result + count) % MOD;
        }
    }

    return result;
}

